     1→/**
     2→ * CONVERGIO EDUCATION - Simple In-Memory Rate Limiter
     3→ *
     4→ * Lightweight rate limiting for API routes without external dependencies.
     5→ * Suitable for MVP/single-instance deployments.
     6→ *
     7→ * For multi-instance production, replace with Redis-based solution.
     8→ */
     9→
    10→interface RateLimitEntry {
    11→  count: number;
    12→  resetTime: number;
    13→}
    14→
    15→// In-memory store (cleared on server restart)
    16→const store = new Map<string, RateLimitEntry>();
    17→
    18→// Cleanup old entries every 5 minutes
    19→const CLEANUP_INTERVAL = 5 * 60 * 1000;
    20→let cleanupTimer: NodeJS.Timeout | null = null;
    21→
    22→function startCleanup() {
    23→  if (cleanupTimer) return;
    24→  cleanupTimer = setInterval(() => {
    25→    const now = Date.now();
    26→    for (const [key, entry] of store.entries()) {
    27→      if (entry.resetTime < now) {
    28→        store.delete(key);
