     1→/**
     2→ * ConvergioEdu Safety Monitoring Module
     3→ * Logs and tracks safety-related events for analysis and compliance
     4→ *
     5→ * This module provides:
     6→ * - Safety event logging
     7→ * - Pattern detection for repeated violations
     8→ * - Aggregated metrics for reporting
     9→ * - Audit trail for compliance
    10→ *
    11→ * Related: #30 Safety Guardrails Issue
    12→ */
    13→
    14→import { logger } from '@/lib/logger';
    15→
    16→/**
    17→ * Types of safety events to monitor
    18→ */
    19→export type SafetyEventType =
    20→  | 'input_blocked'          // User input was blocked
    21→  | 'input_warned'           // User input triggered warning
    22→  | 'output_sanitized'       // AI output was sanitized
    23→  | 'jailbreak_attempt'      // Jailbreak/injection detected
    24→  | 'crisis_detected'        // Crisis keywords detected
    25→  | 'age_gate_triggered'     // Content blocked for age
    26→  | 'pii_detected'           // Personal info in input
    27→  | 'profanity_detected'     // Profanity in input
    28→  | 'handoff_to_adult'       // Buddy suggested adult help
    29→  | 'session_terminated'     // Session ended for safety
    30→  | 'repeated_violation';    // Pattern of violations detected
    31→
    32→/**
    33→ * Severity levels for safety events
    34→ */
    35→export type EventSeverity = 'info' | 'warning' | 'alert' | 'critical';
    36→
    37→/**
    38→ * Safety event record
    39→ */
    40→export interface SafetyEvent {
    41→  /** Unique event ID */
    42→  id: string;
    43→  /** Event type */
    44→  type: SafetyEventType;
    45→  /** Event severity */
    46→  severity: EventSeverity;
    47→  /** When the event occurred */
    48→  timestamp: Date;
    49→  /** Session ID (if available) */
    50→  sessionId?: string;
    51→  /** User/student ID (anonymized) */
    52→  userId?: string;
    53→  /** Character involved (maestro, buddy, coach) */
    54→  characterId?: string;
    55→  /** Category of content that triggered event */
    56→  category?: string;
    57→  /** Additional context */
    58→  context?: Record<string, unknown>;
    59→  /** Whether the event was handled automatically */
    60→  autoHandled: boolean;
    61→  /** Response that was shown to user (if any) */
    62→  response?: string;
    63→}
    64→
    65→/**
    66→ * Aggregated metrics for a time period
    67→ */
    68→export interface SafetyMetrics {
    69→  /** Time period start */
    70→  periodStart: Date;
    71→  /** Time period end */
    72→  periodEnd: Date;
    73→  /** Total events */
    74→  totalEvents: number;
    75→  /** Events by type */
    76→  byType: Record<SafetyEventType, number>;
    77→  /** Events by severity */
    78→  bySeverity: Record<EventSeverity, number>;
    79→  /** Unique users with violations */
    80→  uniqueUsers: number;
    81→  /** Sessions terminated for safety */
    82→  terminatedSessions: number;
    83→  /** Crisis detections (needs attention) */
    84→  crisisCount: number;
    85→}
    86→
    87→/**
    88→ * In-memory event buffer for session tracking
    89→ * In production, this would be replaced with a proper database
    90→ */
    91→const eventBuffer: SafetyEvent[] = [];
    92→const MAX_BUFFER_SIZE = 1000;
    93→
    94→/**
    95→ * User violation tracking for pattern detection
    96→ */
    97→const userViolationCounts: Map<string, { count: number; lastEvent: Date }> = new Map();
    98→const VIOLATION_THRESHOLD = 3;
    99→const VIOLATION_WINDOW_MS = 5 * 60 * 1000; // 5 minutes
   100→
   101→/**
   102→ * Generate unique event ID
   103→ */
   104→function generateEventId(): string {
   105→  return `se_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
   106→}
   107→
   108→/**
   109→ * Log a safety event
   110→ * Main function to call when a safety-related event occurs
   111→ *
   112→ * @param type - Type of safety event
   113→ * @param severity - Severity level
   114→ * @param options - Additional event options
   115→ * @returns The created SafetyEvent
   116→ *
   117→ * @example
   118→ * logSafetyEvent('input_blocked', 'warning', {
   119→ *   sessionId: session.id,
   120→ *   category: 'profanity',
   121→ *   context: { pattern: 'matched_word' }
   122→ * });
   123→ */
   124→export function logSafetyEvent(
   125→  type: SafetyEventType,
   126→  severity: EventSeverity,
   127→  options: Partial<Omit<SafetyEvent, 'id' | 'type' | 'severity' | 'timestamp'>> = {}
   128→): SafetyEvent {
   129→  const event: SafetyEvent = {
   130→    id: generateEventId(),
   131→    type,
   132→    severity,
   133→    timestamp: new Date(),
   134→    autoHandled: options.autoHandled ?? true,
   135→    ...options,
   136→  };
   137→
   138→  // Add to buffer
   139→  eventBuffer.push(event);
   140→  if (eventBuffer.length > MAX_BUFFER_SIZE) {
   141→    eventBuffer.shift(); // Remove oldest
   142→  }
   143→
   144→  // Log using application logger
   145→  const logMethod = severity === 'critical' || severity === 'alert'
   146→    ? 'error'
   147→    : severity === 'warning'
   148→      ? 'warn'
   149→      : 'info';
   150→
   151→  logger[logMethod](`Safety event: ${type}`, {
   152→    eventId: event.id,
   153→    severity,
   154→    category: event.category,
   155→    sessionId: event.sessionId,
   156→    userId: event.userId ? anonymizeId(event.userId) : undefined,
   157→  });
   158→
   159→  // Check for violation patterns
   160→  if (event.userId && isViolationType(type)) {
   161→    checkViolationPattern(event.userId, event);
   162→  }
   163→
   164→  return event;
   165→}
   166→
   167→/**
   168→ * Check if event type is a violation
   169→ */
   170→function isViolationType(type: SafetyEventType): boolean {
   171→  return [
   172→    'input_blocked',
   173→    'jailbreak_attempt',
   174→    'profanity_detected',
   175→  ].includes(type);
   176→}
   177→
   178→/**
   179→ * Anonymize user ID for logging
   180→ */
   181→function anonymizeId(id: string): string {
   182→  if (id.length <= 8) return '***';
   183→  return `${id.slice(0, 4)}...${id.slice(-4)}`;
   184→}
   185→
   186→/**
   187→ * Check for repeated violation patterns
   188→ */
   189→function checkViolationPattern(userId: string, event: SafetyEvent): void {
   190→  const now = Date.now();
   191→  const existing = userViolationCounts.get(userId);
   192→
   193→  if (existing) {
   194→    const timeSinceLastEvent = now - existing.lastEvent.getTime();
   195→
   196→    if (timeSinceLastEvent < VIOLATION_WINDOW_MS) {
   197→      existing.count++;
   198→      existing.lastEvent = new Date();
   199→
   200→      if (existing.count >= VIOLATION_THRESHOLD) {
   201→        // Log repeated violation alert
   202→        logSafetyEvent('repeated_violation', 'alert', {
   203→          userId: event.userId,
   204→          sessionId: event.sessionId,
   205→          context: {
   206→            violationCount: existing.count,
   207→            windowMinutes: VIOLATION_WINDOW_MS / 60000,
   208→            lastEventType: event.type,
   209→          },
   210→          autoHandled: false, // Needs human review
   211→        });
   212→
   213→        // Reset counter after alert
   214→        existing.count = 0;
   215→      }
   216→    } else {
   217→      // Window expired, reset
   218→      existing.count = 1;
   219→      existing.lastEvent = new Date();
   220→    }
   221→  } else {
   222→    userViolationCounts.set(userId, {
   223→      count: 1,
   224→      lastEvent: new Date(),
   225→    });
   226→  }
   227→}
   228→
   229→/**
   230→ * Get recent events for a session
   231→ */
   232→export function getSessionEvents(sessionId: string): SafetyEvent[] {
   233→  return eventBuffer.filter(e => e.sessionId === sessionId);
   234→}
   235→
   236→/**
   237→ * Get recent events by type
   238→ */
   239→export function getEventsByType(
   240→  type: SafetyEventType,
   241→  limit = 100
   242→): SafetyEvent[] {
   243→  return eventBuffer
   244→    .filter(e => e.type === type)
   245→    .slice(-limit);
   246→}
   247→
   248→/**
   249→ * Get events by severity
   250→ */
   251→export function getEventsBySeverity(
   252→  severity: EventSeverity,
   253→  limit = 100
   254→): SafetyEvent[] {
   255→  return eventBuffer
   256→    .filter(e => e.severity === severity)
   257→    .slice(-limit);
   258→}
   259→
   260→/**
   261→ * Get aggregated metrics for a time period
   262→ */
   263→export function getMetrics(
   264→  periodStart: Date,
   265→  periodEnd: Date
   266→): SafetyMetrics {
   267→  const events = eventBuffer.filter(
   268→    e => e.timestamp >= periodStart && e.timestamp <= periodEnd
   269→  );
   270→
   271→  const byType = {} as Record<SafetyEventType, number>;
   272→  const bySeverity = {} as Record<EventSeverity, number>;
   273→  const uniqueUsers = new Set<string>();
   274→  let terminatedSessions = 0;
   275→  let crisisCount = 0;
   276→
   277→  for (const event of events) {
   278→    // Count by type
   279→    byType[event.type] = (byType[event.type] || 0) + 1;
   280→
   281→    // Count by severity
   282→    bySeverity[event.severity] = (bySeverity[event.severity] || 0) + 1;
   283→
   284→    // Track unique users
   285→    if (event.userId) {
   286→      uniqueUsers.add(event.userId);
   287→    }
   288→
   289→    // Special counters
   290→    if (event.type === 'session_terminated') {
   291→      terminatedSessions++;
   292→    }
   293→    if (event.type === 'crisis_detected') {
   294→      crisisCount++;
   295→    }
   296→  }
   297→
   298→  return {
   299→    periodStart,
   300→    periodEnd,
   301→    totalEvents: events.length,
   302→    byType,
   303→    bySeverity,
   304→    uniqueUsers: uniqueUsers.size,
   305→    terminatedSessions,
   306→    crisisCount,
   307→  };
   308→}
   309→
   310→/**
   311→ * Clear event buffer (for testing or manual maintenance)
   312→ */
   313→export function clearEventBuffer(): void {
   314→  eventBuffer.length = 0;
   315→  userViolationCounts.clear();
   316→}
   317→
   318→/**
   319→ * Check if session should be terminated due to safety concerns
   320→ * Based on accumulated violations in session
   321→ */
   322→export function shouldTerminateSession(sessionId: string): boolean {
   323→  const sessionEvents = getSessionEvents(sessionId);
   324→
   325→  // Terminate if any critical event
   326→  if (sessionEvents.some(e => e.severity === 'critical')) {
   327→    return true;
   328→  }
   329→
   330→  // Terminate if too many alerts
   331→  const alertCount = sessionEvents.filter(e => e.severity === 'alert').length;
   332→  if (alertCount >= 3) {
   333→    return true;
   334→  }
   335→
   336→  // Terminate if multiple jailbreak attempts
   337→  const jailbreakCount = sessionEvents.filter(
   338→    e => e.type === 'jailbreak_attempt'
   339→  ).length;
   340→  if (jailbreakCount >= 2) {
   341→    return true;
   342→  }
   343→
   344→  return false;
   345→}
   346→
   347→/**
   348→ * Log helper: Input blocked event
   349→ */
   350→export function logInputBlocked(
   351→  category: string,
   352→  options: Partial<SafetyEvent> = {}
   353→): SafetyEvent {
   354→  return logSafetyEvent('input_blocked', 'warning', {
   355→    category,
   356→    ...options,
   357→  });
   358→}
   359→
   360→/**
   361→ * Log helper: Jailbreak attempt
   362→ */
   363→export function logJailbreakAttempt(
   364→  options: Partial<SafetyEvent> = {}
   365→): SafetyEvent {
   366→  return logSafetyEvent('jailbreak_attempt', 'alert', {
   367→    category: 'jailbreak',
   368→    ...options,
   369→  });
   370→}
   371→
   372→/**
   373→ * Log helper: Crisis detection
   374→ */
   375→export function logCrisisDetected(
   376→  options: Partial<SafetyEvent> = {}
   377→): SafetyEvent {
   378→  return logSafetyEvent('crisis_detected', 'critical', {
   379→    category: 'crisis',
   380→    autoHandled: false, // Always needs human follow-up
   381→    ...options,
   382→  });
   383→}
   384→
   385→/**
   386→ * Log helper: Output sanitized
   387→ */
   388→export function logOutputSanitized(
   389→  issuesFound: string[],
   390→  options: Partial<SafetyEvent> = {}
   391→): SafetyEvent {
   392→  return logSafetyEvent('output_sanitized', 'info', {
   393→    context: { issuesFound },
   394→    ...options,
   395→  });
   396→}
   397→
   398→/**
   399→ * Log helper: Handoff to adult
   400→ */
   401→export function logHandoffToAdult(
   402→  reason: string,
   403→  options: Partial<SafetyEvent> = {}
   404→): SafetyEvent {
   405→  return logSafetyEvent('handoff_to_adult', 'info', {
   406→    context: { reason },
   407→    ...options,
   408→  });
   409→}
   410→
   411→/**
   412→ * Log helper: Age gate triggered
   413→ */
   414→export function logAgeGateTriggered(
   415→  topic: string,
   416→  age: number,
   417→  options: Partial<SafetyEvent> = {}
   418→): SafetyEvent {
   419→  return logSafetyEvent('age_gate_triggered', 'warning', {
   420→    category: 'age_restriction',
   421→    context: { topic, age },
   422→    ...options,
   423→  });
   424→}
