   172→    float32Array[i] = int16Array[i] / (int16Array[i] < 0 ? 0x8000 : 0x7FFF);
   173→  }
   174→  return float32Array;
   175→}
   176→
   177→function resample(inputData: Float32Array, fromRate: number, toRate: number): Float32Array {
   178→  if (fromRate === toRate) return inputData;
   179→  const ratio = fromRate / toRate;
   180→  const outputLength = Math.floor(inputData.length / ratio);
   181→  const output = new Float32Array(outputLength);
   182→  for (let i = 0; i < outputLength; i++) {
   183→    const srcIndex = i * ratio;
   184→    const srcIndexFloor = Math.floor(srcIndex);
   185→    const srcIndexCeil = Math.min(srcIndexFloor + 1, inputData.length - 1);
   186→    const fraction = srcIndex - srcIndexFloor;
   187→    output[i] = inputData[srcIndexFloor] * (1 - fraction) + inputData[srcIndexCeil] * fraction;
   188→  }
   189→  return output;
   190→}
