   267→
   268→  // Stable session ID for the entire voice conversation (used for tool SSE subscriptions)
   269→  const sessionIdRef = useRef<string | null>(null);
   270→
   271→  const [connectionState, setConnectionState] = useState<'idle' | 'connecting' | 'connected' | 'error'>('idle');
   272→
   273→  // ============================================================================
   274→  // AUDIO PLAYBACK (at 24kHz) - SYNC VERSION (like test page that works!)
   275→  // ============================================================================
   276→
   277→  const initPlaybackContext = useCallback(async () => {
   278→    if (playbackContextRef.current) {
   279→      // Resume if suspended (browser policy requires user interaction)
   280→      if (playbackContextRef.current.state === 'suspended') {
   281→        logger.debug('[VoiceSession] 🔊 Resuming suspended AudioContext...');
   282→        await playbackContextRef.current.resume();
   283→      }
   284→      return playbackContextRef.current;
   285→    }
   286→
   287→    const AudioContextClass = window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext;
   288→    // CRITICAL: Create playback context at 24kHz to match Azure output
   289→    playbackContextRef.current = new AudioContextClass({ sampleRate: AZURE_SAMPLE_RATE });
   290→    logger.debug(`[VoiceSession] 🔊 Playback context created at ${AZURE_SAMPLE_RATE}Hz, state: ${playbackContextRef.current.state}`);
   291→
   292→    // Set output device if specified (setSinkId API)
   293→    if (preferredOutputId && 'setSinkId' in playbackContextRef.current) {
   294→      try {
   295→        await (playbackContextRef.current as AudioContext & { setSinkId: (id: string) => Promise<void> }).setSinkId(preferredOutputId);
   296→        logger.debug(`[VoiceSession] 🔊 Audio output set to device: ${preferredOutputId}`);
   297→      } catch (err) {
   298→        logger.warn('[VoiceSession] ⚠️ Could not set output device, using default', { err });
   299→      }
   300→    }
   301→
   302→    // Resume immediately if suspended
   303→    if (playbackContextRef.current.state === 'suspended') {
   304→      logger.debug('[VoiceSession] 🔊 Resuming new AudioContext...');
   305→      await playbackContextRef.current.resume();
   306→    }
   307→
   308→    return playbackContextRef.current;
   309→  }, [preferredOutputId]);
   310→
   311→  // =========================================================================
   312→  // TIME-BASED SCHEDULED PLAYBACK
   313→  // Uses AudioContext.currentTime for precise scheduling to prevent stuttering
   314→  // =========================================================================
   315→
   316→  // Schedule all queued chunks for playback
   317→  const scheduleQueuedChunks = useCallback(() => {
   318→    const ctx = playbackContextRef.current;
   319→    if (!ctx || audioQueueRef.current.length === 0) return;
   320→
   321→    const currentTime = ctx.currentTime;
   322→
   323→    // Schedule chunks from queue
   324→    while (audioQueueRef.current.length > 0) {
   325→      const audioData = audioQueueRef.current.shift()!;
   326→      const float32Data = int16ToFloat32(audioData);
   327→
   328→      // Create buffer at 24kHz
   329→      const buffer = ctx.createBuffer(1, float32Data.length, AZURE_SAMPLE_RATE);
   330→      buffer.getChannelData(0).set(float32Data);
   331→
   332→      const source = ctx.createBufferSource();
   333→      source.buffer = buffer;
   334→      source.connect(ctx.destination);
   335→
   336→      // Calculate chunk duration
   337→      const chunkDuration = float32Data.length / AZURE_SAMPLE_RATE;
   338→
   339→      // Determine when to play this chunk
   340→      // If we're behind schedule, catch up; otherwise schedule ahead
   341→      if (nextPlayTimeRef.current < currentTime + CHUNK_GAP_TOLERANCE) {
   342→        nextPlayTimeRef.current = currentTime + SCHEDULE_AHEAD_TIME;
   343→      }
   344→
   345→      try {
   346→        source.start(nextPlayTimeRef.current);
   347→        scheduledSourcesRef.current.push(source);
   348→
   349→        // Clean up finished sources to prevent memory leak
   350→        source.onended = () => {
   351→          const idx = scheduledSourcesRef.current.indexOf(source);
   352→          if (idx > -1) scheduledSourcesRef.current.splice(idx, 1);
   353→
   354→          // Check if all playback is done
   355→          if (scheduledSourcesRef.current.length === 0 && audioQueueRef.current.length === 0) {
   356→            isPlayingRef.current = false;
   357→            isBufferingRef.current = true; // Reset to buffering for next response
   358→            setSpeaking(false);
   359→            setOutputLevel(0);
   360→          }
   361→        };
   362→
   363→        // Update next play time
   364→        nextPlayTimeRef.current += chunkDuration;
   365→
   366→      } catch (e) {
   367→        logger.error('[VoiceSession] Playback scheduling error', { error: e });
   368→      }
   369→
   370→      // Calculate and update output level (RMS)
   371→      let sumSquares = 0;
   372→      for (let i = 0; i < float32Data.length; i++) {
   373→        sumSquares += float32Data[i] * float32Data[i];
   374→      }
   375→      const rms = Math.sqrt(sumSquares / float32Data.length);
   376→      setOutputLevel(Math.min(rms * 5, 1));
   377→    }
   378→  }, [setSpeaking, setOutputLevel]);
   379→
   380→  // Legacy playNextChunk - now triggers scheduled playback
   381→  const playNextChunk = useCallback(() => {
   382→    const ctx = playbackContextRef.current;
   383→
   384→    if (!ctx || audioQueueRef.current.length === 0) {
   385→      // Check if there are still scheduled sources playing
   386→      if (scheduledSourcesRef.current.length === 0) {
   387→        isPlayingRef.current = false;
   388→        setSpeaking(false);
   389→        setOutputLevel(0);
   390→      }
   391→      return;
   392→    }
   393→
   394→    // If we're in buffering mode, wait for enough chunks
   395→    if (isBufferingRef.current && audioQueueRef.current.length < MIN_BUFFER_CHUNKS) {
   396→      logger.debug(`[VoiceSession] Buffering... ${audioQueueRef.current.length}/${MIN_BUFFER_CHUNKS} chunks`);
   397→      return;
   398→    }
   399→
   400→    // Exit buffering mode and start scheduled playback
   401→    if (isBufferingRef.current) {
   402→      isBufferingRef.current = false;
   403→      nextPlayTimeRef.current = ctx.currentTime + SCHEDULE_AHEAD_TIME;
   404→      logger.debug(`[VoiceSession] Buffer ready, starting scheduled playback at ${nextPlayTimeRef.current.toFixed(3)}`);
   405→    }
   406→
   407→    isPlayingRef.current = true;
   408→    setSpeaking(true);
   409→
   410→    // Schedule all queued chunks
   411→    scheduleQueuedChunks();
   412→  }, [setSpeaking, setOutputLevel, scheduleQueuedChunks]);
   413→
   414→  // Keep ref updated with latest playNextChunk
   415→  useEffect(() => {
   416→    playNextChunkRef.current = playNextChunk;
   417→  }, [playNextChunk]);
   418→
   419→  // ============================================================================
   420→  // AUDIO CAPTURE (at native rate, resample to 24kHz)
   421→  // ============================================================================
   422→
   423→  const startAudioCapture = useCallback(() => {
   424→    if (!captureContextRef.current || !mediaStreamRef.current) {
   425→      logger.warn('[VoiceSession] Cannot start capture: missing context or stream');
   426→      return;
   427→    }
   428→
   429→    const context = captureContextRef.current;
   430→    const nativeSampleRate = context.sampleRate;
   431→    logger.debug(`[VoiceSession] Starting audio capture at ${nativeSampleRate}Hz, resampling to ${AZURE_SAMPLE_RATE}Hz`);
   432→
   433→    const source = context.createMediaStreamSource(mediaStreamRef.current);
   434→    sourceNodeRef.current = source;
   435→
   436→    // Create analyser for input levels
   437→    analyserRef.current = context.createAnalyser();
   438→    analyserRef.current.fftSize = 256;
   439→    source.connect(analyserRef.current);
   440→
   441→    // Create processor for audio capture
   442→    const processor = context.createScriptProcessor(CAPTURE_BUFFER_SIZE, 1, 1);
   443→    processorRef.current = processor;
   444→
   445→    processor.onaudioprocess = (event) => {
   446→      if (wsRef.current?.readyState !== WebSocket.OPEN) return;
   447→      if (isMuted) return;
   448→
   449→      const inputData = event.inputBuffer.getChannelData(0);
   450→
   451→      // Resample from native rate to 24kHz
   452→      const resampledData = resample(inputData, nativeSampleRate, AZURE_SAMPLE_RATE);
   453→
   454→      // Convert to PCM16 and base64
   455→      const int16Data = float32ToInt16(resampledData);
   456→      const base64 = int16ArrayToBase64(int16Data);
   457→
   458→      // Send to Azure
   459→      wsRef.current.send(JSON.stringify({
   460→        type: 'input_audio_buffer.append',
   461→        audio: base64,
   462→      }));
   463→
   464→      // Update input level (throttled)
   465→      const now = performance.now();
   466→      if (now - lastLevelUpdateRef.current > 50 && analyserRef.current) {
   467→        lastLevelUpdateRef.current = now;
   468→        const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
   469→        analyserRef.current.getByteFrequencyData(dataArray);
   470→        const average = dataArray.reduce((a, b) => a + b, 0) / dataArray.length;
   471→        setInputLevel(average / 255);
   472→      }
   473→    };
   474→
   475→    source.connect(processor);
   476→    processor.connect(context.destination);
   477→    logger.debug('[VoiceSession] Audio capture started');
   478→  }, [isMuted, setInputLevel]);
   479→
   480→  // ============================================================================
   481→  // GREETING TRIGGER
   482→  // ============================================================================
   483→
   484→  const sendGreeting = useCallback(() => {
   485→    logger.debug('[VoiceSession] sendGreeting called');
   486→    if (!wsRef.current || wsRef.current.readyState !== WebSocket.OPEN) {
   487→      logger.debug('[VoiceSession] sendGreeting: ws not ready, readyState:', { readyState: wsRef.current?.readyState });
   488→      return;
   489→    }
