   495→    greetingSentRef.current = true;
   496→
   497→    // Get student name from settings store
   498→    const studentName = useSettingsStore.getState().studentProfile?.name || null;
   499→
   500→    const greetingPrompts = [
   501→      `Saluta lo studente${studentName ? ` chiamandolo ${studentName}` : ''} con calore e presentati. Sii coinvolgente ed entusiasta. Poi chiedi cosa vorrebbe imparare oggi.`,
   502→      `Dai il benvenuto allo studente${studentName ? ` (${studentName})` : ''} con la tua personalità caratteristica. Condividi qualcosa di interessante sulla tua materia per suscitare curiosità.`,
   503→      `Inizia la lezione presentandoti nel tuo stile unico${studentName ? ` e rivolgendoti a ${studentName} personalmente` : ''}. Fallo entusiasmare per imparare!`,
   504→    ];
   505→    const greetingPrompt = greetingPrompts[Math.floor(Math.random() * greetingPrompts.length)];
   506→
   507→    logger.debug('[VoiceSession] Sending greeting request...');
   508→
   509→    wsRef.current.send(JSON.stringify({
   510→      type: 'conversation.item.create',
   511→      item: {
