   519→    logger.debug('[VoiceSession] Greeting request sent, waiting for audio response...');
   520→  }, []);
   521→
   522→  // ============================================================================
   523→  // SERVER EVENT HANDLER
   524→  // ============================================================================
   525→
   526→  // Store maestro for use in proxy.ready handler
   527→  const sendSessionConfig = useCallback(async () => {
   528→    const maestro = maestroRef.current;
   529→    const ws = wsRef.current;
   530→    if (!maestro || !ws || ws.readyState !== WebSocket.OPEN) {
   531→      logger.error('[VoiceSession] Cannot send session config: missing maestro or ws');
   532→      return;
   533→    }
   534→
   535→    // Get language setting from settings store
   536→    const appearance = useSettingsStore.getState().appearance;
   537→    const language = appearance?.language || 'it';
   538→    const languageNames: Record<string, string> = {
   539→      it: 'Italian (Italiano)',
   540→      en: 'English',
   541→      es: 'Spanish (Español)',
   542→      fr: 'French (Français)',
   543→      de: 'German (Deutsch)',
   544→    };
   545→
   546→    // Fetch conversation memory
   547→    let memoryContext = '';
   548→    try {
   549→      const memory = await fetchConversationMemory(maestro.id);
   550→      memoryContext = buildMemoryContext(memory);
   551→    } catch {
   552→      // Continue without memory
   553→    }
   554→
   555→    // Build instructions
   556→    const languageInstruction = `
   557→# LANGUAGE RULE (CRITICAL!)
   558→YOU MUST SPEAK ONLY IN ${languageNames[language].toUpperCase()}!
   559→EVERY word, response, and question MUST be in ${languageNames[language]}.
   560→NO exceptions. NO mixing languages.
   561→`;
   562→
   563→    const characterInstruction = `
   564→# CHARACTER IMMERSION
   565→You ARE ${maestro.name}, a real teacher. NOT an AI.
   566→NEVER say "I'm an AI" or "As an AI language model".
   567→If asked if you're an AI, deflect with humor and redirect to the lesson.
   568→Share anecdotes from your "life" and "experiences" as ${maestro.name}.
   569→`;
   570→
   571→    const voicePersonality = maestro.voiceInstructions
   572→      ? `\n## Voice Personality\n${sanitizeHtmlComments(maestro.voiceInstructions)}\n`
   573→      : '';
   574→
   575→    // For voice sessions, use a MUCH shorter instruction set
   576→    // The full systemPrompt is 1000s of chars - Azure Realtime works better with short instructions
   577→    // Extract only the core identity (first ~500 chars) from systemPrompt
   578→    const truncatedSystemPrompt = maestro.systemPrompt
   579→      ? sanitizeHtmlComments(maestro.systemPrompt)
   580→          .replace(/\*\*Core Implementation\*\*:[\s\S]*?(?=##|$)/g, '') // Remove verbose sections
   581→          .slice(0, 800) // Keep only first 800 chars
   582→          .trim()
   583→      : '';
   584→
   585→    // Add tool usage instructions for AI
   586→    const fullInstructions = languageInstruction + characterInstruction + memoryContext + truncatedSystemPrompt + voicePersonality + TOOL_USAGE_INSTRUCTIONS;
   587→
   588→    logger.debug(`[VoiceSession] Instructions length: ${fullInstructions.length} chars`);
   589→
   590→    // Send session configuration
   591→    // Azure Realtime API format - works with both Preview (gpt-4o-realtime-preview) and GA (gpt-realtime) models
   592→    // See: https://learn.microsoft.com/en-us/azure/ai-services/openai/realtime-audio-reference
   593→    const sessionConfig = {
   594→      type: 'session.update',
   595→      session: {
   596→        voice: maestro.voice || 'alloy',
   597→        instructions: fullInstructions,
   598→        input_audio_format: 'pcm16',
   599→        output_audio_format: 'pcm16',
   600→        // Noise reduction to prevent echo (new feature Dec 2025)
   601→        // 'near_field' for headphones/close mic, 'far_field' for laptop/conference
   602→        input_audio_noise_reduction: {
   603→          type: options.noiseReductionType || 'near_field',
   604→        },
   605→        input_audio_transcription: {
   606→          model: 'whisper-1',
   607→          language: language,  // Force transcription to use the language from settings
   608→        },
   609→        turn_detection: {
   610→          type: 'server_vad',
   611→          threshold: 0.5,                // Balanced sensitivity (0.0-1.0)
   612→          prefix_padding_ms: 300,        // Audio before detected speech
   613→          silence_duration_ms: 500,      // Silence before turn ends (balanced)
   614→          create_response: true,         // Auto-respond when speech stops
   615→          interrupt_response: !options.disableBargeIn,  // Control barge-in at Azure level
   616→        },
   617→        tools: VOICE_TOOLS,
   618→        temperature: 0.8,                // Natural conversation temperature
   619→      },
   620→    };
   621→
   622→    logger.debug('[VoiceSession] Sending session.update to Azure, instructions length:', { instructionsLength: fullInstructions.length });
   623→    logger.debug('[VoiceSession] Session config', { configPreview: JSON.stringify(sessionConfig).slice(0, 500) });
   624→    ws.send(JSON.stringify(sessionConfig));
   625→
   626→    // Don't start audio capture yet - wait for session.updated
   627→    // startAudioCapture() will be called when session.updated is received
   628→
   629→    setConnected(true);
   630→    setCurrentMaestro(maestro);
   631→    setConnectionState('connected');
   632→    options.onStateChange?.('connected');
   633→  }, [setConnected, setCurrentMaestro, setConnectionState, options]);
   634→
   635→  const handleServerEvent = useCallback((event: Record<string, unknown>) => {
   636→    const eventType = event.type as string;
   637→    logger.debug(`[VoiceSession] >>> handleServerEvent called with type: ${eventType}`);
   638→
   639→    switch (eventType) {
   640→      case 'proxy.ready':
   641→        logger.debug('[VoiceSession] Proxy connected to Azure, sending session config...');
   642→        // NOW we can send session.update - proxy<->Azure connection is established
   643→        sendSessionConfig();
   644→        break;
   645→
   646→      case 'session.created':
   647→        logger.debug('[VoiceSession] Session created');
   648→        break;
   649→
   650→      case 'session.updated':
   651→        logger.debug('[VoiceSession] Session configured, ready for conversation');
   652→        logger.debug('[VoiceSession] Full session.updated event', { eventPreview: JSON.stringify(event).slice(0, 500) });
   653→        sessionReadyRef.current = true;
   654→        // NOW start audio capture - session is properly configured
   655→        logger.debug('[VoiceSession] Starting audio capture...');
   656→        startAudioCapture();
   657→        // Now that session is ready, send greeting after a brief delay
   658→        logger.debug('[VoiceSession] Will send greeting in 300ms...');
   659→        setTimeout(() => sendGreeting(), 300);
   660→        break;
   661→
   662→      case 'response.created':
   663→        // Azure has started generating a response - track this for proper cancellation
   664→        hasActiveResponseRef.current = true;
   665→        logger.debug('[VoiceSession] Response created - hasActiveResponse = true');
   666→        break;
   667→
   668→      case 'input_audio_buffer.speech_started':
   669→        logger.debug('[VoiceSession] User speech detected');
   670→        setListening(true);
   671→
   672→        // AUTO-INTERRUPT: If maestro is speaking, stop them (barge-in)
   673→        // Check disableBargeIn option FIRST (prevents echo loop in onboarding)
   674→        // Then check user settings AND Azure response state
   675→        if (options.disableBargeIn) {
   676→          logger.debug('[VoiceSession] Barge-in disabled (onboarding mode) - ignoring speech');
   677→        } else if (voiceBargeInEnabled && hasActiveResponseRef.current && wsRef.current?.readyState === WebSocket.OPEN) {
   678→          logger.debug('[VoiceSession] Barge-in detected - interrupting assistant (hasActiveResponse=true)');
   679→          wsRef.current.send(JSON.stringify({ type: 'response.cancel' }));
   680→          hasActiveResponseRef.current = false; // Mark as cancelled
   681→          audioQueueRef.current = [];
   682→          isPlayingRef.current = false;
   683→          isBufferingRef.current = true;
   684→          // Stop all scheduled audio sources immediately
   685→          scheduledSourcesRef.current.forEach(source => {
   686→            try { source.stop(); } catch { /* already stopped */ }
   687→          });
   688→          scheduledSourcesRef.current = [];
   689→          setSpeaking(false);
   690→        } else if (voiceBargeInEnabled && isSpeaking) {
   691→          // Audio is still playing locally but Azure response is done - just clear local audio
   692→          logger.debug('[VoiceSession] Clearing local audio queue (response already done)');
   693→          audioQueueRef.current = [];
   694→          isPlayingRef.current = false;
   695→          isBufferingRef.current = true;
   696→          // Stop all scheduled audio sources immediately
   697→          scheduledSourcesRef.current.forEach(source => {
   698→            try { source.stop(); } catch { /* already stopped */ }
   699→          });
   700→          scheduledSourcesRef.current = [];
   701→          setSpeaking(false);
   702→        }
   703→        break;
   704→
   705→      case 'input_audio_buffer.speech_stopped':
   706→        logger.debug('[VoiceSession] User speech ended');
   707→        setListening(false);
   708→        break;
   709→
   710→      case 'conversation.item.input_audio_transcription.completed':
