// ============================================================================
// TELEMETRY TYPES
// Types for usage tracking, analytics, and Grafana integration
// ============================================================================

/**
 * Telemetry event categories for grouping metrics.
 */
export type TelemetryCategory =
  | 'navigation'     // Page views, tab switches
  | 'education'      // Quizzes, flashcards, mind maps
  | 'conversation'   // Chat messages, voice sessions
  | 'maestro'        // Maestro interactions
  | 'tools'          // Tool usage (calculators, diagrams)
  | 'accessibility'  // A11y feature usage
  | 'error'          // Errors and crashes
  | 'performance';   // Performance metrics (load times, etc.)

/**
 * Individual telemetry event.
 */
export interface TelemetryEvent {
  id: string;
  timestamp: Date;
  category: TelemetryCategory;
  action: string;           // e.g., "page_view", "quiz_started", "voice_session_started"
  label?: string;           // Additional context (page name, maestro ID, etc.)
  value?: number;           // Numeric value (duration, count, etc.)
  metadata?: Record<string, string | number | boolean>;
  sessionId: string;        // Browser session ID
  userId?: string;          // If authenticated
}

/**
 * Aggregated metrics for a time period.
 */
export interface AggregatedMetrics {
  period: 'hour' | 'day' | 'week' | 'month';
  startTime: Date;
  endTime: Date;
  metrics: {
    // General usage
    totalSessions: number;
    uniqueUsers: number;
    avgSessionDuration: number; // minutes

    // Feature usage counts
    pageViews: Record<string, number>;
    maestroUsage: Record<string, number>;
    featureUsage: Record<string, number>;

    // Education metrics
    quizzesStarted: number;
    quizzesCompleted: number;
    flashcardsReviewed: number;
    voiceSessionMinutes: number;

    // Errors
    errorCount: number;
    errorsByType: Record<string, number>;

    // Performance
    avgPageLoadMs: number;
    avgApiResponseMs: number;
  };
}

/**
 * Real-time dashboard data.
 */
export interface RealtimeDashboard {
  activeUsers: number;
  activeSessions: number;
  currentMaestroUsage: Record<string, number>;
  last5MinEvents: number;
  systemHealth: 'healthy' | 'degraded' | 'down';
}

/**
 * Prometheus-compatible metric.
 */
export interface PrometheusMetric {
  name: string;
  type: 'counter' | 'gauge' | 'histogram';
  help: string;
  value: number;
  labels?: Record<string, string>;
}

/**
 * Telemetry configuration.
 */
export interface TelemetryConfig {
  enabled: boolean;
  sampleRate: number;           // 0-1, percentage of events to capture
  batchSize: number;            // Events per batch before sending
  flushIntervalMs: number;      // Auto-flush interval
  maxQueueSize: number;         // Max events in memory queue
  excludeCategories: TelemetryCategory[];
}

/**
 * Time series data point for charts.
 */
export interface TimeSeriesPoint {
  timestamp: Date;
  value: number;
}

/**
 * Chart data for dashboard visualization.
 */
export interface ChartData {
  label: string;
  color: string;
  data: TimeSeriesPoint[];
}

/**
 * Usage statistics for the settings dashboard.
 */
export interface UsageStats {
  // Today's stats
  todaySessions: number;
  todayStudyMinutes: number;
  todayQuestions: number;

  // Weekly stats
  weeklyActiveMinutes: number;
  weeklySessionsCount: number;
  weeklyMaestrosUsed: string[];

  // Historical charts (last 7 days)
  dailyActivityChart: ChartData[];
  featureUsageChart: ChartData[];
  maestroPreferencesChart: ChartData[];

  // Trends
  studyTimeTrend: 'increasing' | 'stable' | 'decreasing';
  engagementScore: number; // 0-100

  // Last updated
  lastUpdated: Date;
}

// ============================================================================
// CONVERGIO WEB - DATABASE SCHEMA
// SQLite for local, PostgreSQL for cloud (same schema works for both)
// ============================================================================

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "sqlite"
}

// ============================================================================
// USER & PROFILE
// ============================================================================

model User {
  id        String   @id @default(cuid())
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  profile       Profile?
  settings      Settings?
  progress      Progress?
  sessions          StudySession[]
  flashcards        FlashcardProgress[]
  quizResults       QuizResult[]
  conversations     Conversation[]
  learnings         Learning[]
  pushSubscriptions PushSubscription[]

  // Issue #64: Consolidated localStorage data
  accessibility     AccessibilitySettings?
  onboarding        OnboardingState?
  pomodoroStats     PomodoroStats?
  calendarEvents    CalendarEvent[]
  htmlSnippets      HtmlSnippet[]
  homeworkSessions  HomeworkSession[]
}

model Profile {
  id            String   @id @default(cuid())
  userId        String   @unique
  user          User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  name          String?
  age           Int?
  schoolYear    Int?
  schoolLevel   String   @default("superiore")
  gradeLevel    String?
  learningGoals String   @default("[]")

  // Character preferences (coach and buddy selection)
  preferredCoach String?  // melissa, roberto, chiara, andrea, favij
  preferredBuddy String?  // mario, noemi, enea, bruno, sofia

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// SETTINGS
// ============================================================================

model Settings {
  id            String  @id @default(cuid())
  userId        String  @unique
  user          User    @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Appearance
  theme         String  @default("system")
  language      String  @default("it")
  accentColor   String  @default("blue")

  // Accessibility
  fontSize           String  @default("medium")
  highContrast       Boolean @default(false)
  dyslexiaFont       Boolean @default(false)
  reducedMotion      Boolean @default(false)
  voiceEnabled       Boolean @default(true)
  simplifiedLanguage Boolean @default(false)
  adhdMode           Boolean @default(false)

  // AI Provider
  provider      String  @default("azure")
  model         String  @default("gpt-4o")
  budgetLimit   Float   @default(50.0)
  totalSpent    Float   @default(0.0)

  // Parent Mode Consent (Issue #63)
  parentChatConsentAt DateTime?  // When parent consented to chat with professors

  // Parent Dashboard (Issue #64)
  parentDashboardLastViewed DateTime?  // When parent last viewed the dashboard

  // Azure Cost Configuration
  azureCostConfig String?  // JSON: {token_cost, audio_cost, etc.}

  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt
}

// ============================================================================
// PROGRESS & GAMIFICATION
// ============================================================================

model Progress {
  id                String    @id @default(cuid())
  userId            String    @unique
  user              User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  xp                Int       @default(0)
  level             Int       @default(1)

  // Streak
  streakCurrent     Int       @default(0)
  streakLongest     Int       @default(0)
  lastStudyDate     DateTime?

  // Aggregates
  totalStudyMinutes Int       @default(0)
  questionsAsked    Int       @default(0)
  sessionsThisWeek  Int       @default(0)

  // Complex data as JSON
  achievements      String    @default("[]")
  masteries         String    @default("[]")

  createdAt         DateTime  @default(now())
  updatedAt         DateTime  @updatedAt
}

model StudySession {
  id          String    @id @default(cuid())
  userId      String
  user        User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  maestroId   String
  subject     String
  startedAt   DateTime  @default(now())
  endedAt     DateTime?
  duration    Int?
  xpEarned    Int       @default(0)
  questions   Int       @default(0)

  // Student self-evaluation (1-5 stars)
  studentRating    Int?
  studentFeedback  String?

  // AI Maestro evaluation (1-10 score)
  maestroScore     Int?
  maestroFeedback  String?
  strengths        String?   // JSON array
  areasToImprove   String?   // JSON array

  // Session context
  topics           String    @default("[]") // JSON array of topics covered
  conversationId   String?   // Link to Conversation

  // Tools created during session
  materials        Material[]

  @@index([userId])
  @@index([startedAt])
  @@index([conversationId])
}

// ============================================================================
// EDUCATION: FLASHCARDS & QUIZZES
// ============================================================================

model FlashcardProgress {
  id             String    @id @default(cuid())
  userId         String
  user           User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  cardId         String
  deckId         String?

  // FSRS Algorithm State
  difficulty     Float     @default(0.0)
  stability      Float     @default(0.0)
  retrievability Float     @default(1.0)
  state          String    @default("new")

  // Review tracking
  reps           Int       @default(0)
  lapses         Int       @default(0)
  lastReview     DateTime?
  nextReview     DateTime?

  createdAt      DateTime  @default(now())
  updatedAt      DateTime  @updatedAt

  @@unique([userId, cardId])
  @@index([userId])
  @@index([nextReview])
}

model QuizResult {
  id             String   @id @default(cuid())
  userId         String
  user           User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  quizId         String
  subject        String?
  score          Int
  totalQuestions Int
  percentage     Float

  // Detailed answers as JSON
  answers        String   @default("[]")

  completedAt    DateTime @default(now())

  @@index([userId])
  @@index([completedAt])
}

// ============================================================================
// CONVERSATIONS & MEMORY
// ============================================================================

model Conversation {
  id           String    @id @default(cuid())
  userId       String
  user         User      @relation(fields: [userId], references: [id], onDelete: Cascade)

  maestroId    String
  title        String?

  // Summary system
  summary      String?
  keyFacts     String?
  topics       String    @default("[]")

  // Message management
  messageCount Int       @default(0)
  messages     Message[]

  // Status
  isActive     Boolean   @default(true)
  lastMessageAt DateTime?

  // Parent Mode (Issue #63)
  isParentMode Boolean   @default(false)
  studentId    String?   // The student being discussed (for parent conversations)

  createdAt    DateTime  @default(now())
  updatedAt    DateTime  @updatedAt

  @@index([userId])
  @@index([maestroId])
  @@index([updatedAt])
  @@index([isParentMode])
}

model Message {
  id             String       @id @default(cuid())
  conversationId String
  conversation   Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)

  role           String
  content        String

  // Optional metadata
  toolCalls      String?
  tokenCount     Int?

  createdAt      DateTime     @default(now())

  @@index([conversationId])
  @@index([createdAt])
}

// ============================================================================
// LEARNINGS (Cross-session insights)
// ============================================================================

model Learning {
  id          String   @id @default(cuid())
  userId      String
  user        User     @relation(fields: [userId], references: [id], onDelete: Cascade)

  // Context
  maestroId   String?
  subject     String?

  // The learning itself
  category    String
  insight     String

  // Confidence tracking
  confidence  Float    @default(0.5)
  occurrences Int      @default(1)

  // Timestamps
  createdAt   DateTime @default(now())
  lastSeen    DateTime @updatedAt

  lastSeen    DateTime @updatedAt

  @@index([userId])
  @@index([category])
  @@index([confidence])
}

// ============================================================================
// STUDENT INSIGHT PROFILES (Multi-Maestro Learning Insights for Parents)
// Related: Issue #31
// ============================================================================

model StudentInsightProfile {
  id           String    @id @default(cuid())
  userId       String    @unique
  studentName  String

  // Access control (GDPR)
  visibleTo    String    @default("parents") // parents | teachers | both

  // Consent tracking
  parentConsent   Boolean  @default(false)
  studentConsent  Boolean  @default(false)
  consentDate     DateTime?
  deletionRequested DateTime?

  // Synthesized profile data as JSON
  insights     String    @default("[]") // MaestroInsight[]
  strengths    String    @default("[]") // StrengthArea[]
  growthAreas  String    @default("[]") // GrowthArea[]
  learningStyle String   @default("{}") // LearningStyle
  strategies   String    @default("[]") // Strategy[]

  // Historical snapshots
  progressHistory String  @default("[]") // ProfileSnapshot[]

  // Metadata
  sessionCount  Int       @default(0)
  lastSessionId String?
  confidenceScore Float   @default(0.0)

  createdAt    DateTime  @default(now())
  updatedAt    DateTime  @updatedAt

  // Access log for GDPR audit
  accessLogs   ProfileAccessLog[]

  @@index([userId])
}

model ProfileAccessLog {
  id         String   @id @default(cuid())
  profileId  String
  profile    StudentInsightProfile @relation(fields: [profileId], references: [id], onDelete: Cascade)

  userId     String
  action     String   // view | download | share | edit | delete_request
  details    String?
  ipAddress  String?
  userAgent  String?

  timestamp  DateTime @default(now())

  @@index([profileId])
  @@index([timestamp])
}

// ============================================================================
// NOTIFICATIONS (Server-side persistence for cross-device sync)
// ============================================================================

model Notification {
  id          String   @id @default(cuid())
  userId      String

  type        String   // achievement | streak | reminder | break | session_end | level_up | calendar | system | flashcard_due | scheduled_session | suggestion
  title       String
  message     String
  actionUrl   String?
  metadata    String?  // JSON for additional data

  // Scheduler-specific fields (Issue #27)
  priority     String?  // high | medium | low
  relatedId    String?  // Reference to flashcard deck, session, etc.
  melissaVoice String?  // Voice script for Melissa TTS

  read        Boolean  @default(false)
  dismissed   Boolean  @default(false)

  // Scheduling for future notifications
  scheduledFor DateTime?
  sentAt       DateTime?

  createdAt   DateTime @default(now())
  expiresAt   DateTime? // Auto-delete after expiry

  @@index([userId])
  @@index([read])
  @@index([createdAt])
  @@index([scheduledFor])
}

// ============================================================================
// TELEMETRY (Usage Analytics & Grafana Integration)
// ============================================================================

model TelemetryEvent {
  id          String   @id @default(cuid())
  eventId     String   @unique // Client-generated event ID for deduplication

  // Event data
  timestamp   DateTime
  category    String   // navigation | education | conversation | maestro | tools | accessibility | error | performance
  action      String   // Specific action (page_view, quiz_started, etc.)
  label       String?  // Additional context (page name, maestro ID, etc.)
  value       Float?   // Numeric value (duration, count, etc.)
  metadata    String?  // JSON for additional key-value pairs

  // Session & user tracking
  sessionId   String
  userId      String?  // Optional, only if authenticated

  createdAt   DateTime @default(now())

  @@index([userId])
  @@index([sessionId])
  @@index([timestamp])
  @@index([category])
  @@index([action])
}

// ============================================================================
// METHOD PROGRESS (Autonomy Tracking - Issue #28)
// ============================================================================

model MethodProgress {
  id        String @id @default(cuid())
  userId    String @unique

  // Skill progress (JSON stored)
  mindMaps       String @default("{}") // MindMapProgress JSON
  flashcards     String @default("{}") // FlashcardProgress JSON
  selfAssessment String @default("{}") // SelfAssessmentProgress JSON
  helpBehavior   String @default("{}") // HelpBehavior JSON
  methodTransfer String @default("{}") // MethodTransfer JSON

  // Events history (JSON array)
  events String @default("[]") // MethodEvent[] JSON

  // Computed scores
  autonomyScore Float @default(0) // 0-1

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  @@index([userId])
  @@index([autonomyScore])
}

// ============================================================================
// MATERIALS (Persisted tool outputs - T-20)
// ============================================================================

model Material {
  id          String   @id @default(cuid())
  userId      String
  toolId      String   @unique // Client-generated tool ID
  toolType    String   // mindmap, quiz, flashcard, demo, etc.
  title       String
  content     String   // JSON string

  // Context
  maestroId   String?
  sessionId   String?
  session     StudySession? @relation(fields: [sessionId], references: [id])
  subject     String?
  preview     String?  // Preview text for lists

  // Migrated from CreatedTool
  topic          String?
  conversationId String?

  // Status
  status      String   @default("active") // active, archived, deleted

  // User interaction (Issue #37 - Archive features)
  userRating   Int?     // 1-5 stars
  isBookmarked Boolean  @default(false)
  viewCount    Int      @default(0)

  // Full-text search (ADR 0022 - Knowledge Hub)
  searchableText String?  // Pre-computed searchable content for Fuse.js

  // Organization (ADR 0022 - Knowledge Hub)
  collectionId String?
  collection   Collection? @relation(fields: [collectionId], references: [id])
  tags         MaterialTag[]

  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt

// ============================================================================
// API ROUTE: Chat completions
// Supports: Azure OpenAI, Ollama (local)
// NEVER: Direct OpenAI API, Anthropic
// SECURITY: Input/output filtering for child safety (Issue #30)
// FEATURE: Function calling for tool execution (Issue #39)
// ============================================================================

import { NextRequest, NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { chatCompletion, getActiveProvider, type AIProvider } from '@/lib/ai/providers';
import { prisma } from '@/lib/db';
import { logger } from '@/lib/logger';
import { checkRateLimit, getClientIdentifier, RATE_LIMITS, rateLimitResponse } from '@/lib/rate-limit';
import { filterInput, sanitizeOutput } from '@/lib/safety';
import { CHAT_TOOL_DEFINITIONS } from '@/types/tools';
import { executeToolCall } from '@/lib/tools/tool-executor';
import { loadPreviousContext } from '@/lib/conversation/memory-loader';
import { enhanceSystemPrompt } from '@/lib/conversation/prompt-enhancer';
// Import handlers to register them
import '@/lib/tools/handlers';

interface ChatMessage {
  role: 'user' | 'assistant' | 'system';
  content: string;
}

interface ChatRequest {
  messages: ChatMessage[];
  systemPrompt: string;
  maestroId: string;
  enableTools?: boolean; // Optional: enable tool calling (default: true)
  enableMemory?: boolean; // Optional: enable conversation memory (default: true)
  requestedTool?: 'mindmap' | 'quiz' | 'flashcard' | 'demo' | 'summary'; // Tool context injection
}

// Tool context to inject into system prompt (Phase 5: Chat API Enhancement)
const TOOL_CONTEXT: Record<string, string> = {
  mindmap: `
STAI CREANDO UNA MAPPA MENTALE con lo studente.
Linee guida:
- Fai domande maieutiche per esplorare l'argomento
- Parti dal concetto centrale e espandi in modo organico
- Usa create_mindmap per costruire la mappa incrementalmente
- Ogni risposta dello studente può aggiungere nodi alla mappa
- Mantieni la struttura chiara e gerarchica`,

  quiz: `
STAI CREANDO UN QUIZ con lo studente.

**REGOLA IMPORTANTE:** Prima di creare il quiz, CHIEDI allo studente:
"Preferisci fare il quiz per iscritto (lo vedi sullo schermo) oppure a voce (te lo faccio io)?"

Se sceglie PER ISCRITTO:
- Chiedi prima di che argomento vuole essere interrogato
- Crea domande a scelta multipla chiare e formative
- Usa create_quiz per generare il quiz
- Includi feedback educativo per ogni risposta
- Adatta la difficoltà al livello dello studente

Se sceglie A VOCE (o se siete in una sessione vocale):
- NON usare create_quiz!
- Fai tu le domande una alla volta nella chat
- Elenca le opzioni (A, B, C, D)
- Aspetta la risposta dello studente
- Conferma se è corretta o spiega perché è sbagliata
- Passa alla domanda successiva
- Alla fine dai un resoconto del punteggio`,

  flashcard: `
STAI CREANDO FLASHCARD per lo studente.
Linee guida:
- Identifica i concetti chiave da memorizzare
- Crea carte con domanda/risposta brevi e incisive
- Usa create_flashcards per generare le carte
- Organizza le carte per argomento o difficoltà
